const { Client } = require('pg');

const client = new Client({
  user: 'postgres',
  password: '',
  host: 'localhost',
  database: 'your_database_name',
});

client.connect().then(() => {
  console.log('Connected to PostgreSQL database');
});

// Create a table
client.query('CREATE TABLE users (id SERIAL PRIMARY KEY, name VARCHAR(255), email VARCHAR(255))').then(() => {
  console.log('Table users created');
});

// Insert a new user
client.query('INSERT INTO users (name, email) VALUES ($1, $2)', ['John Doe', 'john@example.com']).then(() => {
  console.log('New user inserted');
});

// Read all users
client.query('SELECT * FROM users').then((result) => {
  console.log(result.rows);
});

// Update a user
client.query('UPDATE users SET name = $1 WHERE id = $2', ['Jane Doe', 1]).then(() => {
  console.log('User updated');
});

// Delete a user
client.query('DELETE FROM users WHERE id = $1', [1]).then(() => {
  console.log('User deleted');
});

client.end().then(() => {
  console.log('Disconnected from PostgreSQL database');
});